select count(*) from postgres.posts as p, postgres.postlinks as pl, postgres.posthistory as ph, postgres.votes as v, postgres.badges as b, postgres.users as u where p.id = pl.relatedpostid and u.id = p.owneruserid and u.id = b.userid and u.id = ph.userid and u.id = v.userid and p.answercount>=0 and p.favoritecount>=0 and pl.linktypeid=1 and ph.posthistorytypeid=2 and v.creationdate>=timestamp '2010-07-20 00:00:00' and u.reputation>=1 and u.downvotes>=0 and u.downvotes<=0 and u.upvotes<=439 and u.creationdate<=timestamp '2014-08-07 11:18:45';
